import type { ProductResearchContent } from './productResearchContent'

type ResearchSeed = Omit<ProductResearchContent, 'faq'>

function withResearchFaq(name: string, seed: ResearchSeed): ProductResearchContent {
  return {
    ...seed,
    faq: [
      { question: `What type of research material is ${name}?`, answer: seed.scientificIdentity },
      { question: `What pathway is ${name} studied in?`, answer: seed.mechanismSummary },
      { question: 'What is the strongest evidence category?', answer: `The page classifies the current evidence profile as: ${seed.evidenceProfile}. Each study card identifies its own model and limitations.` },
      { question: 'Does this page provide treatment or administration guidance?', answer: 'No. This catalog material is presented strictly for Research Use Only. The page contains no dosing, administration, treatment, or personalized-use instructions.' },
    ],
  }
}

